  ('two-sum-stub', 'Two Sum', 'arrays', 'Easy', 'Given an array of integers and a target, return the indices of the two numbers that add up to the target. Assume exactly one solution.', ARRAY['array', 'hash-map']::TEXT[], 'twoSum', '[{"name":"nums","type":"int[]"},{"name":"target","type":"int"}]'::jsonb, 'int[]', '[{"inputs":["[2,7,11,15]","9"],"expected":"[0,1]"},{"inputs":["[3,2,4]","6"],"expected":"[1,2]"}]'::jsonb, 'both'),
